# --- 4. Response Logging (After Request) ---
@app.after_request
def log_response_details(response):
    response_summary = {
        'request_id': getattr(g, 'request_id', 'N/A'), # Get request_id from g object
        'status_code': response.status_code,
        'headers': dict(response.headers),
        # Attempt to log response body, handling different content types
        'response_body': response.get_data(as_text=True) if response.is_json or 'text' in response.content_type else '[Binary Data]'
    }
    logger.debug(f"[{getattr(g, 'request_id', 'N/A')}] Outgoing Response Details: {json.dumps(response_summary, indent=2)}")
    return response

# --- 5. Error Logging (Error Handler) ---
@app.errorhandler(Exception)
def handle_exception(e):
    # Log the exception with traceback for detailed debugging
    request_id = getattr(g, 'request_id', 'N/A')
    logger.exception(f"[{request_id}] Unhandled Exception occurred during request processing: {e}")

    # Return a generic error message to the client, hiding internal details in production
    response = jsonify({
        'request_id': request_id,
        'error': 'An internal server error occurred',
        'message': str(e) # Include exception message for debugging in development, remove for production
    })
    response.status_code = 500
    return response

